+      runBestEffortCleanup({
+        cleanup: async () => 7,
+      }),
+    ).resolves.toBe(7);
+  });
+
+  it("swallows cleanup failures and reports them through onError", async () => {
+    const onError = vi.fn();
+    const error = new Error("cleanup failed");
+
+    await expect(
+      runBestEffortCleanup({
+        cleanup: async () => {
+          throw error;
+        },
